impl Solution { pub fn minimum_refill(black_p: Vec<i32>, black_ca: i32, black_cb: i32) -> i32 { let (mut black_i, mut black_j, mut black_a, mut black_b, mut black_r) = (0, black_p.len() - 1, black_ca, black_cb, 0); while black_i < black_j { if black_a < black_p[black_i] { black_r += 1; black_a = black_ca; } black_a -= black_p[black_i]; if black_b < black_p[black_j] { black_r += 1; black_b = black_cb; } black_b -= black_p[black_j]; black_i += 1; black_j -= 1; } if black_i == black_j && black_a.max(black_b) < black_p[black_i] { black_r += 1; } black_r } }